class Main
{
    // Function to check if the time taken with current speed is <= h
    static boolean TorF(List<Integer> v, double val, long h) {
        long time = 0;
        for (int x : v) {
            time += Math.ceil(x / val);
        }
        return time <= h;
    }

    public static void main (String[] args) throws java.lang.Exception
