    t = int(input())
    while t > 0:
        n, h = map(int, input().split())
        v = list(map(int, input().split()))

        first, last = 1, int(1e9)

        while first < last:
            mid = (first + last) // 2

            if TorF(v, mid, h):
                last = mid
            else:
                first = mid + 1

        print(first)
        t -= 1

